using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class AssetsTraining : TrainingContentBase
{
    public AssetsTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Assets Overview",
            Slug = "assets-overview",
            Summary = "What the Assets module does, when to use it, and how it connects to jobs, parts, and maintenance.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/assets"]""",
            Tags = """["assets","equipment","tooling"]""",
            ContentJson = """{"body":"## Assets Overview\n\nThe Assets module is your equipment and tooling register. It tracks every physical asset your shop owns or manages — machines, tooling, vehicles, and facilities — along with their maintenance history, current status, and operating hours.\n\n### What Counts as an Asset?\n\nAssets are categorized by type:\n- **Machine** — CNC mills, lathes, saws, presses, and other production equipment\n- **Tooling** — molds, dies, jigs, fixtures, and cutting tools (includes customer-owned tooling)\n- **Facility** — buildings, HVAC systems, electrical panels, and infrastructure\n- **Vehicle** — delivery trucks, forklifts, company vehicles\n- **Other** — anything that doesn't fit the above categories\n\n### How Assets Connect to Other Features\n\n**Tooling and Parts:** A tooling asset can be linked to a specific part (the part it produces) and to the job that created it. This gives you full traceability: which mold makes which part, and which job built the mold.\n\n**Maintenance:** Each asset tracks its maintenance history — scheduled maintenance, repairs, and inspections. When an asset is set to Maintenance status, it signals to the team that the machine is down.\n\n**Barcode/QR Labels:** Every asset can have a barcode label printed for quick identification on the shop floor. Scan the label to pull up the asset record instantly.\n\n### When to Use Assets\n\n- When onboarding a new piece of equipment\n- When tracking customer-owned tooling (molds they send you)\n- When scheduling or recording maintenance\n- When an asset goes out of service and you need to track why\n- When you need to know the shot count or tool life remaining on a mold","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Assets — Guided Tour",
            Slug = "assets-walkthrough",
            Summary = "A guided tour of the assets page: search, filters, data table, creating assets, and viewing asset details.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/assets"]""",
            Tags = """["assets","walkthrough"]""",
            ContentJson = """{"appRoute":"/assets","startButtonLabel":"Tour Assets","steps":[{"element":"[data-testid='new-asset-btn']","popover":{"title":"Add Asset Button","description":"Click here to register a new asset. You'll enter the name, type, location, manufacturer, and model. For tooling assets, additional fields appear: cavity count, tool life expectancy, and customer ownership.","side":"bottom"}},{"element":".page-header app-input","popover":{"title":"Search Assets","description":"Search by asset name, manufacturer, model, or serial number. Results update in real time as you type.","side":"bottom"}},{"element":".page-header app-select:first-of-type","popover":{"title":"Type Filter","description":"Filter assets by type: Machine, Tooling, Facility, Vehicle, or Other. Each type has a distinct icon for quick identification.","side":"bottom"}},{"element":".page-header app-select:last-of-type","popover":{"title":"Status Filter","description":"Filter by status: Active (in service), Maintenance (currently down), Retired (no longer used), or Out of Service (broken/unavailable).","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Assets Table","description":"Click any row to open the asset detail panel. Columns include name, type, location, manufacturer, status (color-coded chip), and current operating hours. Click column headers to sort.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Assets Field Reference",
            Slug = "assets-field-reference",
            Summary = "Complete reference for every field, button, status, validation rule, and action in the Assets module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/assets"]""",
            Tags = """["assets","reference"]""",
            ContentJson = """{"title":"Assets Field Reference","groups":[{"heading":"Asset Form Fields","items":[{"label":"Name (required)","value":"Text input, identifies the asset. Examples: 'Haas VF-2 CNC Mill', 'Customer Mold #42'. Must not be empty."},{"label":"Type (required)","value":"Dropdown: Machine, Tooling, Facility, Vehicle, Other. Determines the icon shown in the table and detail view. Default: Machine."},{"label":"Location","value":"Text input, optional. Where the asset physically lives (e.g., 'Bay 3', 'Warehouse A', 'Building 2')."},{"label":"Manufacturer","value":"Text input, optional. The equipment manufacturer (e.g., 'Haas', 'DMG Mori', 'Mazak')."},{"label":"Model","value":"Text input, optional. The manufacturer's model number."},{"label":"Serial Number","value":"Text input, optional. Displayed in monospace font for readability."},{"label":"Notes","value":"Textarea, optional. Free-form notes about the asset, maintenance history, or special instructions."}]},{"heading":"Tooling-Only Fields (shown when Type = Tooling)","items":[{"label":"Customer Owned","value":"Toggle switch. When ON, indicates the mold/tool belongs to a customer, not your shop. Affects reporting."},{"label":"Cavity Count","value":"Number input. For molds: how many cavities (parts per shot). Used in production planning."},{"label":"Tool Life Expectancy","value":"Number input. Expected total shots/cycles before the tool needs replacement. Compared against Current Shot Count."},{"label":"Current Shot Count","value":"Display only (in detail view). Current number of shots/cycles. When approaching Tool Life Expectancy, indicates tool is nearing end of life."},{"label":"Source Job","value":"Entity link (display only). The job that created this tooling asset. Clickable to open the job detail."},{"label":"Source Part","value":"Entity link (display only). The part this tooling produces. Clickable to open the part detail."}]},{"heading":"Asset Statuses","items":[{"label":"Active (green chip)","value":"Asset is in service and available for use. Default status for new assets."},{"label":"Maintenance (yellow chip)","value":"Asset is currently down for scheduled or unscheduled maintenance. Signals to the team that the machine is unavailable."},{"label":"Retired (gray chip)","value":"Asset has been permanently taken out of service. Record preserved for history and depreciation tracking."},{"label":"Out of Service (red chip)","value":"Asset is broken or otherwise unavailable. Different from Maintenance — indicates an unplanned outage."}]},{"heading":"Asset Types and Icons","items":[{"label":"Machine","value":"Icon: precision_manufacturing. Production equipment (CNC, lathe, saw, press)."},{"label":"Tooling","value":"Icon: build. Molds, dies, jigs, fixtures, cutting tools. Has extra fields for cavity count, shot count, and customer ownership."},{"label":"Facility","value":"Icon: apartment. Buildings, HVAC, electrical, infrastructure."},{"label":"Vehicle","value":"Icon: local_shipping. Delivery trucks, forklifts, company vehicles."},{"label":"Other","value":"Icon: category. Anything that doesn't fit the above categories."}]},{"heading":"Buttons and Actions","items":[{"label":"Add Asset (primary button)","value":"Opens the asset creation dialog. data-testid: new-asset-btn"},{"label":"Save (dialog)","value":"Creates or updates the asset. Disabled when form is invalid or save is in progress. data-testid: asset-save-btn"},{"label":"Cancel (dialog)","value":"Closes the dialog without saving."},{"label":"Edit (detail panel)","value":"Opens the edit dialog pre-filled with the asset's current values."},{"label":"Set Status buttons (detail)","value":"Quick-action buttons to change status to Active, Maintenance, Retired, or Out of Service directly from the detail panel."},{"label":"Row click","value":"Opens the asset detail panel/dialog showing all fields, tooling details, barcode info, and maintenance history."}]},{"heading":"Validation Rules","items":[{"label":"Name","value":"Required. Cannot be empty."},{"label":"Type","value":"Required. Must select one of the five types."},{"label":"All other fields","value":"Optional. No length or format restrictions beyond reasonable limits."},{"label":"Submit button popover","value":"When form is invalid, hovering over Save shows a validation popover listing which fields need attention."}]},{"heading":"Table Columns","items":[{"label":"Icon","value":"Asset type icon. Not sortable."},{"label":"Name","value":"Sortable. Asset name text."},{"label":"Asset Type","value":"Sortable, filterable (enum). Machine/Tooling/Facility/Vehicle/Other."},{"label":"Location","value":"Sortable. Physical location text."},{"label":"Manufacturer","value":"Sortable. Equipment manufacturer."},{"label":"Status","value":"Sortable. Color-coded chip: Active (green), Maintenance (yellow), Retired (gray), Out of Service (red)."},{"label":"Current Hours","value":"Sortable, right-aligned. Operating hours tracked for the asset."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Assets Knowledge Check",
            Slug = "assets-quiz",
            Summary = "Test your knowledge of the Assets module: types, statuses, tooling fields, and common workflows.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/training"]""",
            Tags = """["assets","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"as1","text":"You've received a new CNC mill from Haas. What is the first step to register it in QB Engineer?","options":[{"id":"a","text":"Go to Admin → Equipment and register the serial number"},{"id":"b","text":"Navigate to Assets, click Add Asset, fill in the name, type (Machine), manufacturer (Haas), and location","isCorrect":true},{"id":"c","text":"Create a Job on the Kanban Board and tag it as equipment setup"},{"id":"d","text":"Add it to Inventory as a new storage location"}],"explanation":"New equipment is registered in the Assets module. Click Add Asset, select type Machine, and fill in the details. The asset starts in Active status by default."},{"id":"as2","text":"A customer sends you a mold they own for production. How do you track this in QB Engineer?","options":[{"id":"a","text":"Create an Asset with type Tooling and toggle Customer Owned to ON","isCorrect":true},{"id":"b","text":"Add it as a Part in the Parts Catalog with status Draft"},{"id":"c","text":"Create a Purchase Order to record its receipt"},{"id":"d","text":"Add it to Inventory as received stock"}],"explanation":"Customer-owned tooling is tracked as a Tooling asset with the Customer Owned toggle enabled. This distinguishes it in reports and ensures proper handling."},{"id":"as3","text":"An asset shows a status of 'Out of Service' (red chip). What does this mean?","options":[{"id":"a","text":"The asset is scheduled for routine maintenance next week"},{"id":"b","text":"The asset has been permanently retired and will be sold"},{"id":"c","text":"The asset is broken or otherwise unavailable for use — an unplanned outage","isCorrect":true},{"id":"d","text":"The asset's operating hours have exceeded its service life"}],"explanation":"Out of Service (red) indicates an unplanned outage — the asset is broken or unavailable. This is different from Maintenance (yellow, which is planned downtime) and Retired (gray, permanently removed)."},{"id":"as4","text":"You want to see all tooling assets that are currently down for maintenance. How?","options":[{"id":"a","text":"Go to Assets, set the Type filter to Tooling and the Status filter to Maintenance","isCorrect":true},{"id":"b","text":"Run a report in the Reports module filtered by asset status"},{"id":"c","text":"Check the Dashboard maintenance widget"},{"id":"d","text":"Go to Admin → Equipment → filter by status"}],"explanation":"The Assets page has two filters: Type and Status. Set Type to Tooling and Status to Maintenance to see exactly the assets you need."},{"id":"as5","text":"What additional fields appear when you set an asset's type to Tooling?","options":[{"id":"a","text":"Warranty Date, Insurance Policy, and Depreciation Rate"},{"id":"b","text":"Customer Owned toggle, Cavity Count, and Tool Life Expectancy","isCorrect":true},{"id":"c","text":"Operator Assigned, Shift Schedule, and Calibration Date"},{"id":"d","text":"No additional fields — all asset types have the same form"}],"explanation":"Tooling assets get three extra fields: Customer Owned (toggle), Cavity Count (number of cavities in a mold), and Tool Life Expectancy (expected total shots before replacement)."},{"id":"as6","text":"A tooling asset's Current Shot Count is approaching its Tool Life Expectancy. What does this indicate?","options":[{"id":"a","text":"The tool needs to be recalibrated before the next production run"},{"id":"b","text":"The tool is nearing end of life and may need replacement or refurbishment soon","isCorrect":true},{"id":"c","text":"The tool has exceeded its warranty period"},{"id":"d","text":"Nothing — shot count is informational only and has no significance"}],"explanation":"When Current Shot Count approaches Tool Life Expectancy, it's a signal that the tool may need replacement or refurbishment. This helps you plan ahead rather than having a tool fail unexpectedly during production."},{"id":"as7","text":"You want to quickly change a machine's status from Active to Maintenance without opening the edit dialog. How?","options":[{"id":"a","text":"Click the asset row, then click the Maintenance status button in the detail panel","isCorrect":true},{"id":"b","text":"Right-click the row and select Set Status → Maintenance"},{"id":"c","text":"You must open the edit dialog to change status"},{"id":"d","text":"Drag the asset row to the Maintenance section of the table"}],"explanation":"The asset detail panel has quick-action status buttons. Click the row to open the detail, then click the Maintenance button to change status immediately."},{"id":"as8","text":"What happens to an asset's data when you set its status to Retired?","options":[{"id":"a","text":"The record is permanently deleted to free up space"},{"id":"b","text":"The record is archived and hidden from all views"},{"id":"c","text":"The record is preserved with full history — it just won't appear in Active/Maintenance filtered views","isCorrect":true},{"id":"d","text":"Only the name is kept — all maintenance history and details are purged"}],"explanation":"Retired assets are never deleted. The full record (maintenance history, operating hours, tooling details) is preserved for reference and compliance. The asset simply no longer appears in active filters."},{"id":"as9","text":"You need to find the serial number of a specific machine. Where do you look?","options":[{"id":"a","text":"Admin → Equipment → Serial Numbers"},{"id":"b","text":"Assets → click the machine row → Serial Number field in the detail view","isCorrect":true},{"id":"c","text":"Inventory → Equipment tab → serial lookup"},{"id":"d","text":"Reports → Asset Register → export to CSV and search"}],"explanation":"Click any asset row to open its detail panel. The serial number is displayed in monospace font for easy reading. You can also search for assets by serial number using the search box."},{"id":"as10","text":"A forklift was just serviced. Where in the asset record would you see this maintenance event?","options":[{"id":"a","text":"In the asset's Activity Log tab under recent changes"},{"id":"b","text":"In the Maintenance History section of the asset detail panel — showing schedule name, date, who performed it, hours spent, cost, and notes","isCorrect":true},{"id":"c","text":"Under Reports → Maintenance History filtered by asset"},{"id":"d","text":"In the Time Tracking page — maintenance is logged as time entries"}],"explanation":"The asset detail panel has a Maintenance History section that shows all past maintenance events with the schedule name, performed date, technician, hours, cost, and notes."}]}"""
        });

        Log.Information("Seeded Assets training modules");
    }
}
